sql:
SELECT users.username, users.department 
FROM users 
JOIN filings ON users.user_id = filings.created_by_user_id;

external_knowledge:
- Threshold for tardy submissions: more than 100 submissions;
- 'Heavy late-filers' refers to users with a high number of late filings;
- 'Types of forms they've submitted' refers to the form types associated with the filings made by those users.

sql:
SELECT form_id, form_type, description, version, status
FROM forms
WHERE status = 'active';

SELECT * 
FROM filings
WHERE approval_date > submission_deadline;

SELECT created_by_user_id
FROM filings
WHERE received_date = (
    SELECT MIN(received_date)
    FROM filings
);

SELECT AVG(filing_count) 
FROM (
  SELECT COUNT(*) as filing_count 
  FROM filings 
  GROUP BY created_by_user_id
) as user_filing_counts;

SELECT body_name
FROM regulatory_bodies
WHERE website LIKE 'www%';

SELECT AVG(total_filings) 
FROM (
  SELECT created_by_user_id, COUNT(filing_id) AS total_filings
  FROM filings
  GROUP BY created_by_user_id
) AS user_filing_counts;

SELECT COUNT(*) 
FROM filings 
WHERE is_late = 1;

SELECT f.form_id, f.form_type, f.description, f.version, f.created_date, f.updated_date, f.status
FROM forms f
WHERE f.form_id IN (SELECT form_id FROM filings);
